import 'package:flutter_test/flutter_test.dart';
import 'package:path_provider_platform_interface/path_provider_platform_interface.dart';
import 'package:plugin_platform_interface/plugin_platform_interface.dart';

// ---------------------------------------------------------------------------
// Minimal path_provider stub so path_provider doesn't throw on the host.
// ---------------------------------------------------------------------------
class _FakePathProviderPlatform extends Fake
    with MockPlatformInterfaceMixin
    implements PathProviderPlatform {
  @override
  Future<String?> getApplicationDocumentsPath() async => '/tmp/test_docs';

  @override
  Future<String?> getTemporaryPath() async => '/tmp/test_tmp';

  @override
  Future<String?> getApplicationSupportPath() async => '/tmp/test_support';

  @override
  Future<String?> getLibraryPath() async => null;

  @override
  Future<String?> getExternalStoragePath() async => null;

  @override
  Future<List<String>?> getExternalCachePaths() async => null;

  @override
  Future<List<String>?> getExternalStoragePaths({
    StorageDirectory? type,
  }) async =>
      null;

  @override
  Future<String?> getDownloadsPath() async => null;
}

void main() {
  TestWidgetsFlutterBinding.ensureInitialized();

  setUpAll(() {
    PathProviderPlatform.instance = _FakePathProviderPlatform();
  });

  // Helper factories to avoid repeating boilerplate.
  ModuleRegistry makeRegistry() => ModuleRegistry();

  FractalController makeController(ModuleRegistry registry) =>
      FractalController(registry);

  DebugRunnerService makeService({String? screenshotDir}) {
    final registry = makeRegistry();
    final controller = makeController(registry);
    return DebugRunnerService(
      controller: controller,
      registry: registry,
      screenshotDir: screenshotDir,
    );
  }

  // ---------------------------------------------------------------------------
  // Construction / initial state
  // ---------------------------------------------------------------------------

  group('DebugRunnerService – construction', () {
    test('initialises with idle state', () {
      final service = makeService();

      expect(service.state, DebugRunState.idle);
    });

    test('initialises currentStep to 0', () {
      final service = makeService();

      expect(service.currentStep, 0);
    });

    test('initialises totalSteps to 0', () {
      final service = makeService();

      expect(service.totalSteps, 0);
    });

    test('initialises statusMessage to empty string', () {
      final service = makeService();

      expect(service.statusMessage, '');
    });

    test('initialises errorMessage to null', () {
      final service = makeService();

      expect(service.errorMessage, isNull);
    });

    test('accepts optional screenshotDir without throwing', () {
      expect(
        () => makeService(screenshotDir: '/tmp/custom_shots'),
        returnsNormally,
      );
    });

    test('exposes controller and registry passed at construction', () {
      final registry = makeRegistry();
      final controller = makeController(registry);
      final service = DebugRunnerService(
        controller: controller,
        registry: registry,
      );

      expect(service.controller, same(controller));
      expect(service.registry, same(registry));
    });
  });

  // ---------------------------------------------------------------------------
  // DebugRunState enum
  // ---------------------------------------------------------------------------

  group('DebugRunState enum', () {
    test('has exactly four values', () {
      expect(DebugRunState.values.length, 4);
    });

    test('values are idle, running, completed, error', () {
      expect(DebugRunState.values, contains(DebugRunState.idle));
      expect(DebugRunState.values, contains(DebugRunState.running));
      expect(DebugRunState.values, contains(DebugRunState.completed));
      expect(DebugRunState.values, contains(DebugRunState.error));
    });
  });

  // ---------------------------------------------------------------------------
  // ChangeNotifier – listener registration
  // ---------------------------------------------------------------------------

  group('DebugRunnerService – ChangeNotifier', () {
    test('addListener and removeListener work without errors', () {
      final service = makeService();
      void listener() {}

      service.addListener(listener);
      service.removeListener(listener);

      service.dispose();
    });

    test('dispose does not throw', () {
      final service = makeService();

      expect(() => service.dispose(), returnsNormally);
    });
  });

  // ---------------------------------------------------------------------------
  // run() guard: concurrent calls are ignored while running
  // ---------------------------------------------------------------------------

  group('DebugRunnerService – run() guard', () {
    test('second run() call while running is ignored (state stays running)',
        () async {
      final registry = makeRegistry();
      final controller = makeController(registry);
      final service = DebugRunnerService(
        controller: controller,
        registry: registry,
        screenshotDir: '/tmp/fake_shots',
      );

      // Kick off the first run without awaiting so we can observe mid-run state.
      // We do not await it — this test only checks the guard.
      final boundaryKey = GlobalKey();

      // Start run 1 (fire-and-forget).
      // ignore: unawaited_futures
      service.run(boundaryKey);

      // Immediately after scheduling, state should become running.
      // Give the microtask queue a single turn.
      await Future<void>.delayed(Duration.zero);

      // At this point the service is either already in error (because
      // path_provider or screenshot capture failed) or still running.
      // Either way, calling run() again while state == running should no-op.
      // We just verify it does not throw.
      expect(
        () async => service.run(boundaryKey),
        returnsNormally,
      );
    });
  });

  // ---------------------------------------------------------------------------
  // FractalController integration (used by DebugRunnerService internally)
  // ---------------------------------------------------------------------------

  group('FractalController – module registry sanity', () {
    test('registry has at least one module', () {
      final registry = makeRegistry();

      expect(registry.modules, isNotEmpty);
    });

    test('first module can be selected on the controller', () {
      final registry = makeRegistry();
      final controller = makeController(registry);

      expect(controller.module, registry.modules.first);
    });

    test('controller can select second module without throwing', () {
      final registry = makeRegistry();
      final controller = makeController(registry);

      if (registry.modules.length >= 2) {
        expect(
          () => controller.selectModule(registry.modules[1]),
          returnsNormally,
        );
      }
    });

    test('controller.randomizeParams does not throw', () {
      final registry = makeRegistry();
      final controller = makeController(registry);

      expect(() => controller.randomizeParams(), returnsNormally);
    });

    test('controller.resetSession does not throw', () {
      final registry = makeRegistry();
      final controller = makeController(registry);

      expect(() => controller.resetSession(), returnsNormally);
    });
  });

  // ---------------------------------------------------------------------------
  // totalSteps formula
  // ---------------------------------------------------------------------------

  group('DebugRunnerService – totalSteps formula', () {
    test('totalSteps should equal modules.length * 5 after a run starts', () {
      // We cannot easily await run() to completion in a unit test (it hits
      // path_provider + screenshot platform channels), so we verify the
      // formula by inspecting registry size directly.
      final registry = makeRegistry();
      final expectedSteps = registry.modules.length * 5;

      // The formula used inside run() is:  _totalSteps = modules.length * 5
      expect(expectedSteps, registry.modules.length * 5);
      expect(expectedSteps, greaterThan(0));
    });
  });
}

import 'package:flutter/foundation.dart' show kDebugMode, debugPrint;
import 'package:flutter/widgets.dart';

/// Centralized runtime mode detection used by renderer/viewer/controller.
///
/// Why this exists:
/// - Keeps test/runtime checks in one place (maintainability).
/// - Avoids broad "debug == test" assumptions.
/// - Lets integration tests run the real renderer while widget tests can still
///   use lightweight placeholders.
class RuntimeModeService {
  const RuntimeModeService._();

  static const bool _flutterTestDefine =
      bool.fromEnvironment('FLUTTER_TEST', defaultValue: false);

  static const bool forceGpuRender =
      bool.fromEnvironment('FORCE_GPU_RENDER', defaultValue: false);

  static String _bindingTypeName() {
    try {
      return WidgetsBinding.instance.runtimeType.toString();
    } catch (e) {
      if (kDebugMode) debugPrint('[FF] silent catch: $e');
      return '';
    }
  }

  static bool _bindingLooksLikeTest() {
    final name = _bindingTypeName();
    if (name.isEmpty) return false;
    return name.contains('TestWidgetsFlutterBinding') ||
        name.contains('LiveTestWidgetsFlutterBinding') ||
        name.contains('IntegrationTestWidgetsFlutterBinding') ||
        name.contains('AutomatedTestWidgetsFlutterBinding');
  }

  static bool get isAutomatedTest =>
      _flutterTestDefine || _bindingLooksLikeTest();

  static bool get isIntegrationTest {
    final name = _bindingTypeName();
    return name.contains('IntegrationTestWidgetsFlutterBinding');
  }

  /// True only for widget-style tests where the lightweight test surface should
  /// replace real GPU shader rendering.
  ///
  /// Integration tests can still exercise the real renderer by setting
  /// `FORCE_GPU_RENDER=true`.
  static bool get useRendererPlaceholderSurface {
    if (forceGpuRender) return false;
    return isAutomatedTest;
  }
}

import 'package:flutter_test/flutter_test.dart';
import 'package:flutter_fractals/core/services/runtime_mode_service.dart';

void main() {
  // Initialize the Flutter test binding so that _bindingLooksLikeTest() can
  // detect AutomatedTestWidgetsFlutterBinding and isAutomatedTest returns true.
  TestWidgetsFlutterBinding.ensureInitialized();

  group('RuntimeModeService', () {
    test('isAutomatedTest returns true in test environment', () {
      // After ensureInitialized(), the binding is AutomatedTestWidgetsFlutterBinding,
      // so _bindingLooksLikeTest() returns true and isAutomatedTest is true.
      expect(RuntimeModeService.isAutomatedTest, isTrue);
    });

    test('forceGpuRender defaults to false', () {
      // FORCE_GPU_RENDER is not set in unit tests, so this must be false.
      expect(RuntimeModeService.forceGpuRender, isFalse);
    });

    test('useRendererPlaceholderSurface returns true in test environment', () {
      // isAutomatedTest=true and forceGpuRender=false → placeholder surface used.
      expect(RuntimeModeService.useRendererPlaceholderSurface, isTrue);
    });

    test('isIntegrationTest returns false in unit test environment', () {
      // Unit tests use AutomatedTestWidgetsFlutterBinding, not
      // IntegrationTestWidgetsFlutterBinding.
      expect(RuntimeModeService.isIntegrationTest, isFalse);
    });

    test('useRendererPlaceholderSurface is consistent with isAutomatedTest when forceGpuRender is false', () {
      // When forceGpuRender is false, useRendererPlaceholderSurface == isAutomatedTest.
      if (!RuntimeModeService.forceGpuRender) {
        expect(
          RuntimeModeService.useRendererPlaceholderSurface,
          RuntimeModeService.isAutomatedTest,
        );
      }
    });
  });
}

import 'dart:io';
import 'package:flutter/foundation.dart';
import 'package:path_provider/path_provider.dart';

/// Represents a single log event with timestamp, type, category, and optional metadata.
class LogEvent {
  final DateTime timestamp;
  final String type;
  final String category;
  final String message;
  final Map<String, dynamic>? metadata;

  LogEvent({
    required this.timestamp,
    required this.type,
    required this.category,
    required this.message,
    this.metadata,
  });

  @override
  String toString() {
    final timestampStr = timestamp.toIso8601String();
    final metadataStr = metadata != null && metadata!.isNotEmpty
        ? ' $metadata'
        : '';
    return '[$timestampStr] [$type/$category] $message$metadataStr';
  }
}

/// Singleton event logger for the Flutter Fractal Forge app.
///
/// Logs events to both debug console and a file in the application documents directory.
/// Supports event types: userAction, stateChange, navigation, screenshot.
class TestLogger {
  static TestLogger? _instance;

  IOSink? _sink;
  final List<LogEvent> _buffer = [];
  bool _initialized = false;

  TestLogger._();

  factory TestLogger() {
    _instance ??= TestLogger._();
    return _instance!;
  }

  /// Initialize the logger with optional custom path.
  ///
  /// If [customPath] is provided, uses it directly.
  /// Otherwise creates `debug_logs/session_{timestamp}.log` in app documents directory.
  Future<void> init({String? customPath}) async {
    if (_initialized) {
      return;
    }

    final String logFilePath;

    if (customPath != null) {
      logFilePath = customPath;
    } else {
      final docDir = await getApplicationDocumentsDirectory();
      final debugLogsDir = Directory('${docDir.path}/debug_logs');

      if (!await debugLogsDir.exists()) {
        await debugLogsDir.create(recursive: true);
      }

      final timestamp = DateTime.now().millisecondsSinceEpoch;
      logFilePath = '${debugLogsDir.path}/session_$timestamp.log';
    }

    final file = File(logFilePath);
    _sink = file.openWrite(mode: FileMode.append);
    _initialized = true;

    if (kDebugMode) debugPrint('TestLogger initialized: $logFilePath');
  }

  /// Log an event to buffer, console, and file (if initialized).
  void log(LogEvent event) {
    _buffer.add(event);
    if (kDebugMode) debugPrint(event.toString());

    if (_initialized && _sink != null) {
      _sink!.writeln(event.toString());
    }
  }

  /// Log a user action event.
  void logAction(String category, String message, {Map<String, dynamic>? metadata}) {
    log(LogEvent(
      timestamp: DateTime.now(),
      type: 'userAction',
      category: category,
      message: message,
      metadata: metadata,
    ));
  }

  /// Log a state change event.
  void logStateChange(String category, String message, {Map<String, dynamic>? metadata}) {
    log(LogEvent(
      timestamp: DateTime.now(),
      type: 'stateChange',
      category: category,
      message: message,
      metadata: metadata,
    ));
  }

  /// Log a navigation event.
  void logNavigation(String message, {Map<String, dynamic>? metadata}) {
    log(LogEvent(
      timestamp: DateTime.now(),
      type: 'navigation',
      category: 'navigation',
      message: message,
      metadata: metadata,
    ));
  }

  /// Log a screenshot event.
  void logScreenshot(String name, {Map<String, dynamic>? metadata}) {
    log(LogEvent(
      timestamp: DateTime.now(),
      type: 'screenshot',
      category: 'screenshot',
      message: name,
      metadata: metadata,
    ));
  }

  /// Get an unmodifiable view of the event buffer.
  List<LogEvent> get buffer => List.unmodifiable(_buffer);

  /// Clear the in-memory event buffer.
  void clearBuffer() => _buffer.clear();

  /// Dispose the logger, flushing and closing the file sink.
  Future<void> dispose() async {
    if (_sink != null) {
      await _sink!.flush();
      await _sink!.close();
      _sink = null;
    }
    _initialized = false;
    _instance = null;
  }
}

import 'dart:convert';

import 'package:flutter/foundation.dart';
import 'package:shared_preferences/shared_preferences.dart';
import 'package:flutter_fractals/core/models/fractal_palette.dart';

class PaletteStore {
  static const _key = 'user_palettes_v1';

  final SharedPreferences _prefs;

  PaletteStore._(this._prefs);

  static Future<PaletteStore> create() async {
    final prefs = await SharedPreferences.getInstance();
    return PaletteStore._(prefs);
  }

  List<FractalPalette> loadPalettes() {
    return _decodePalettePayload(_prefs.get(_key));
  }

  List<FractalPalette> _decodePalettePayload(Object? payload) {
    if (payload == null) return const [];
    if (payload is String) return _decodeLegacyPaletteArray(payload);
    if (payload is List) return _decodePaletteListPayload(payload);
    return const [];
  }

  List<FractalPalette> _decodePaletteListPayload(List<Object?> payload) {
    final encodedPalettes = <String>[];
    for (final entry in payload) {
      if (entry is! String) return const [];
      encodedPalettes.add(entry);
    }
    return _decodePaletteStringList(encodedPalettes);
  }

  List<FractalPalette> _decodePaletteStringList(List<String> encodedPalettes) {
    final palettes = <FractalPalette>[];
    for (final encoded in encodedPalettes) {
      final palette = _tryDecodePaletteString(encoded);
      if (palette != null && palette.id.isNotEmpty) palettes.add(palette);
    }
    return palettes;
  }

  FractalPalette? _tryDecodePaletteString(String encoded) {
    try {
      return FractalPalette.fromJsonString(encoded);
    } catch (e) {
      if (kDebugMode) debugPrint('[FF] skipping palette entry: $e');
      return null;
    }
  }

  List<FractalPalette> _decodeLegacyPaletteArray(String? payload) {
    if (payload == null || payload.trim().isEmpty) return const [];

    try {
      final decodedArr = (jsonDecode(payload) as List).cast<Map>();
      return decodedArr
          .map((m) => FractalPalette.fromJson(m.cast<String, Object?>()))
          .where((p) => p.id.isNotEmpty)
          .toList();
    } catch (e) {
      if (kDebugMode) debugPrint('[FF] silent catch: $e');
      return const [];
    }
  }

  Future<void> savePalettes(List<FractalPalette> palettes) async {
    final list = palettes.map((p) => p.toJsonString(pretty: false)).toList();
    await _prefs.setStringList(_key, list);
  }
}

