import 'dart:async';
import 'package:flutter/material.dart';
import 'package:vector_math/vector_math.dart' hide Colors;

/// Replayable decision for [AnimatedFractalController.animateParameter].
///
/// Parameter animation only supports numeric interpolation. Keeping that
/// contract explicit prevents unsupported boolean/string changes from arming a
/// transition that no animation can ever complete.
enum AnimatedParameterTransitionKind {
  unchanged,
  numeric,
  unsupported,
}

/// Pure parameter-transition plan derived from two parameter values.
final class AnimatedParameterTransitionPlan {
  final AnimatedParameterTransitionKind kind;
  final double? fromValue;
  final double? toValue;

  const AnimatedParameterTransitionPlan._({
    required this.kind,
    this.fromValue,
    this.toValue,
  });

  factory AnimatedParameterTransitionPlan.fromValues(Object from, Object to) {
    if (from == to) {
      return const AnimatedParameterTransitionPlan._(
        kind: AnimatedParameterTransitionKind.unchanged,
      );
    }

    if (from is num && to is num) {
      return AnimatedParameterTransitionPlan._(
        kind: AnimatedParameterTransitionKind.numeric,
        fromValue: from.toDouble(),
        toValue: to.toDouble(),
      );
    }

    return const AnimatedParameterTransitionPlan._(
      kind: AnimatedParameterTransitionKind.unsupported,
    );
  }

  bool get startsTransition => kind == AnimatedParameterTransitionKind.numeric;
}

/// Replayable frame plan for timer-driven animations.
///
/// Morph timers derive curve input from a duration and frame cadence. Keeping
/// that conversion explicit prevents sub-frame durations from producing zero
/// total steps and sending Infinity/NaN into Flutter curves.
final class AnimatedTimelinePlan {
  static const int defaultFramesPerSecond = 60;

  final Duration duration;
  final int framesPerSecond;
  final Duration frameInterval;
  final int totalFrames;

  const AnimatedTimelinePlan._({
    required this.duration,
    required this.framesPerSecond,
    required this.frameInterval,
    required this.totalFrames,
  })  : assert(framesPerSecond > 0, 'framesPerSecond must be positive'),
        assert(frameInterval > Duration.zero, 'frameInterval must be positive'),
        assert(totalFrames > 0, 'totalFrames must be positive');

  factory AnimatedTimelinePlan.forDuration(
    Duration duration, {
    int framesPerSecond = defaultFramesPerSecond,
  }) {
    final safeFramesPerSecond =
        framesPerSecond > 0 ? framesPerSecond : defaultFramesPerSecond;
    final frameIntervalMs = 1000 ~/ safeFramesPerSecond;
    final rawFrames = duration.inMicroseconds <= 0
        ? 1
        : (duration.inMicroseconds *
                safeFramesPerSecond /
                Duration.microsecondsPerSecond)
            .round();

    return AnimatedTimelinePlan._(
      duration: duration,
      framesPerSecond: safeFramesPerSecond,
      frameInterval: Duration(
        milliseconds: frameIntervalMs > 0 ? frameIntervalMs : 1,
      ),
      totalFrames: rawFrames > 0 ? rawFrames : 1,
    );
  }

  bool get isImmediate => duration <= Duration.zero;

  double progressForFrame(int frame) {
    if (frame <= 0) return 0.0;
    return (frame / totalFrames).clamp(0.0, 1.0).toDouble();
  }

  bool isCompleteFrame(int frame) => frame >= totalFrames;
}

/// Replayable progress contract for elapsed timer animations.
///
/// Parameter/view animations are driven by wall-clock elapsed time. A
/// non-positive duration is an immediate transition, matching morph timelines;
/// otherwise a negative duration can leave an animation permanently at 0%.
final class AnimatedElapsedProgress {
  final Duration duration;
  final Duration elapsed;

  const AnimatedElapsedProgress({
    required this.duration,
    required this.elapsed,
  });

  double get value {
    if (duration <= Duration.zero) return 1.0;
    if (elapsed <= Duration.zero) return 0.0;
    return (elapsed.inMicroseconds / duration.inMicroseconds)
        .clamp(0.0, 1.0)
        .toDouble();
  }

  bool get isComplete => value >= 1.0;
}

/// Service that manages smooth animated transitions for fractal parameters.
///
/// This service provides interpolated values for parameters during transitions,
/// enabling smooth morphing effects when changing fractal settings.
class AnimatedFractalController extends ChangeNotifier {
  /// Animation duration for parameter changes.
  final Duration parameterDuration;

  /// Animation duration for module (fractal type) changes.
  final Duration morphDuration;

  /// Animation curve for transitions.
  final Curve curve;

  // Internal state
  final Map<String, _AnimatedValue> _animatedParams = {};
  _AnimatedValue<double>? _animatedZoom;
  _AnimatedValue<Vector2>? _animatedPan;
  _AnimatedValue<Vector3>? _animatedRotation;

  String? _previousModuleId;
  String? _currentModuleId;
  double _morphProgress = 1.0;
  Timer? _morphTimer;
  Timer? _celebrationTimer;

  bool _isCelebrating = false;
  bool _isTransitioning = false;

  // Interesting spot detection
  int _interestingSpotCount = 0;
  DateTime? _lastInterestingSpotTime;
  final _interestingSpotController = StreamController<void>.broadcast();

  AnimatedFractalController({
    this.parameterDuration = const Duration(milliseconds: 250),
    this.morphDuration = const Duration(milliseconds: 600),
    this.curve = Curves.easeOutCubic,
  });

  /// Stream that emits when an interesting spot is found.
  Stream<void> get onInterestingSpot => _interestingSpotController.stream;

  /// Whether a celebration effect should be shown.
  bool get isCelebrating => _isCelebrating;

  /// Whether the controller is currently transitioning between states.
  bool get isTransitioning => _isTransitioning;

  /// Progress of the current morph transition (0.0 to 1.0).
  double get morphProgress => _morphProgress;

  /// The previous module ID during a morph transition.
  String? get previousModuleId => _previousModuleId;

  /// The current module ID.
  String? get currentModuleId => _currentModuleId;

  /// Start a parameter transition.
  void animateParameter(String id, Object from, Object to) {
    final plan = AnimatedParameterTransitionPlan.fromValues(from, to);
    if (!plan.startsTransition) return;

    _isTransitioning = true;
    notifyListeners();

    _animatedParams[id] = _AnimatedValue<double>(
      from: plan.fromValue!,
      to: plan.toValue!,
      duration: parameterDuration,
      curve: curve,
      onComplete: () {
        _animatedParams.remove(id);
        _checkTransitionComplete();
      },
    );

    notifyListeners();
  }

  /// Animate zoom level transition.
  void animateZoom(double from, double to) {
    if (from == to) return;

    _isTransitioning = true;
    _animatedZoom = _AnimatedValue<double>(
      from: from,
      to: to,
      duration: parameterDuration,
      curve: curve,
      onComplete: () {
        _animatedZoom = null;
        _checkTransitionComplete();
      },
    );
    notifyListeners();
  }

  /// Animate pan transition.
  void animatePan(Vector2 from, Vector2 to) {
    if (from.x == to.x && from.y == to.y) return;

    _isTransitioning = true;
    _animatedPan = _AnimatedValue<Vector2>(
      from: from.clone(),
      to: to.clone(),
      duration: parameterDuration,
      curve: curve,
      onComplete: () {
        _animatedPan = null;
        _checkTransitionComplete();
      },
    );
    notifyListeners();
  }

  /// Animate rotation transition.
  void animateRotation(Vector3 from, Vector3 to) {
    if (from.x == to.x && from.y == to.y && from.z == to.z) return;

    _isTransitioning = true;
    _animatedRotation = _AnimatedValue<Vector3>(
      from: from.clone(),
      to: to.clone(),
      duration: parameterDuration,
      curve: curve,
      onComplete: () {
        _animatedRotation = null;
        _checkTransitionComplete();
      },
    );
    notifyListeners();
  }

  /// Start a module morph transition.
  void startMorph(String fromModuleId, String toModuleId) {
    if (fromModuleId == toModuleId) return;

    _previousModuleId = fromModuleId;
    _currentModuleId = toModuleId;
    _morphProgress = 0.0;
    _isTransitioning = true;

    _morphTimer?.cancel();

    final timeline = AnimatedTimelinePlan.forDuration(morphDuration);
    if (timeline.isImmediate) {
      _finishMorphTransition();
      notifyListeners();
      return;
    }

    var step = 0;

    _morphTimer = Timer.periodic(
      timeline.frameInterval,
      (timer) {
        step++;
        _morphProgress = curve.transform(timeline.progressForFrame(step));
        notifyListeners();

        if (timeline.isCompleteFrame(step)) {
          timer.cancel();
          _finishMorphTransition();
          notifyListeners();
        }
      },
    );

    notifyListeners();
  }

  /// Get the interpolated value for a parameter.
  Object? getInterpolatedValue(String id, Object currentValue) {
    final animated = _animatedParams[id];
    if (animated == null) return null;

    if (animated is _AnimatedValue<double>) {
      return animated.currentValue;
    }
    return null;
  }

  /// Get the interpolated zoom value.
  double? get interpolatedZoom => _animatedZoom?.currentValue;

  /// Get the interpolated pan value.
  Vector2? get interpolatedPan => _animatedPan?.currentValue;

  /// Get the interpolated rotation value.
  Vector3? get interpolatedRotation => _animatedRotation?.currentValue;

  /// Record when the user finds an interesting spot.
  ///
  /// Triggers celebration effects when multiple interesting spots
  /// are found in quick succession.
  void recordInterestingSpot() {
    final now = DateTime.now();

    if (_lastInterestingSpotTime != null) {
      final elapsed = now.difference(_lastInterestingSpotTime!);
      if (elapsed.inSeconds < 30) {
        _interestingSpotCount++;

        // Trigger celebration after finding 3 interesting spots quickly
        if (_interestingSpotCount >= 3) {
          _triggerCelebration();
          _interestingSpotCount = 0;
        }
      } else {
        _interestingSpotCount = 1;
      }
    } else {
      _interestingSpotCount = 1;
    }

    _lastInterestingSpotTime = now;
    _interestingSpotController.add(null);
  }

  void _triggerCelebration() {
    _isCelebrating = true;
    notifyListeners();

    // Reset celebration after animation. Keep the timer cancellable so a
    // disposed controller cannot receive a delayed notifyListeners callback.
    _celebrationTimer?.cancel();
    _celebrationTimer = Timer(const Duration(milliseconds: 2500), () {
      _celebrationTimer = null;
      _isCelebrating = false;
      notifyListeners();
    });
  }

  /// Manually trigger a celebration effect.
  void celebrate() {
    _triggerCelebration();
  }

  void _finishMorphTransition() {
    _morphProgress = 1.0;
    _previousModuleId = null;
    _checkTransitionComplete();
  }

  void _checkTransitionComplete() {
    if (_animatedParams.isEmpty &&
        _animatedZoom == null &&
        _animatedPan == null &&
        _animatedRotation == null &&
        _morphProgress >= 1.0) {
      _isTransitioning = false;
      notifyListeners();
    }
  }

  /// Update all animations for the current frame.
  void tick() {
    var needsUpdate = false;

    if (_tickAnimatedParameters()) needsUpdate = true;

    if (_animatedZoom?.tick() == true) needsUpdate = true;
    if (_animatedPan?.tick() == true) needsUpdate = true;
    if (_animatedRotation?.tick() == true) needsUpdate = true;

    if (needsUpdate) {
      notifyListeners();
    }
  }

  bool _tickAnimatedParameters() {
    var needsUpdate = false;

    // Completion callbacks remove entries from [_animatedParams]. Snapshot the
    // values first so a completed parameter does not mutate the map currently
    // being iterated.
    for (final animated in _animatedParams.values.toList(growable: false)) {
      if (animated.tick()) {
        needsUpdate = true;
      }
    }

    return needsUpdate;
  }

  @override
  void dispose() {
    _morphTimer?.cancel();
    _celebrationTimer?.cancel();

    // Close stream controller before disposing
    if (!_interestingSpotController.isClosed) {
      _interestingSpotController.close();
    }

    super.dispose();
  }
}

/// Internal animated value helper.
class _AnimatedValue<T> {
  final T from;
  final T to;
  final Duration duration;
  final Curve curve;
  final VoidCallback? onComplete;

  final DateTime _startTime = DateTime.now();
  bool _completed = false;

  _AnimatedValue({
    required this.from,
    required this.to,
    required this.duration,
    required this.curve,
    this.onComplete,
  });

  AnimatedElapsedProgress get _elapsedProgress => AnimatedElapsedProgress(
        duration: duration,
        elapsed: DateTime.now().difference(_startTime),
      );

  double get _progress => _elapsedProgress.value;

  double get _curvedProgress => curve.transform(_progress);

  bool get isComplete => _elapsedProgress.isComplete;

  T get currentValue {
    final t = _curvedProgress;

    if (T == double) {
      return _lerpDouble(from as double, to as double, t) as T;
    } else if (T == Vector2) {
      return _lerpVector2(from as Vector2, to as Vector2, t) as T;
    } else if (T == Vector3) {
      return _lerpVector3(from as Vector3, to as Vector3, t) as T;
    }
    return to;
  }

  double _lerpDouble(double a, double b, double t) => a + (b - a) * t;

  Vector2 _lerpVector2(Vector2 a, Vector2 b, double t) {
    return Vector2(
      a.x + (b.x - a.x) * t,
      a.y + (b.y - a.y) * t,
    );
  }

  Vector3 _lerpVector3(Vector3 a, Vector3 b, double t) {
    return Vector3(
      a.x + (b.x - a.x) * t,
      a.y + (b.y - a.y) * t,
      a.z + (b.z - a.z) * t,
    );
  }

  /// Returns true if the animation is still running.
  bool tick() {
    if (_completed) return false;

    if (isComplete && !_completed) {
      _completed = true;
      onComplete?.call();
      return false;
    }

    return !_completed;
  }
}

/// Mixin to add animation capabilities to FractalController.
mixin AnimatedFractalMixin on ChangeNotifier {
  AnimatedFractalController? _animationController;

  /// The animation controller for smooth transitions.
  AnimatedFractalController get animationController {
    _animationController ??= AnimatedFractalController();
    return _animationController!;
  }

  /// Set a custom animation controller.
  set animationController(AnimatedFractalController controller) {
    _animationController = controller;
  }

  @override
  void dispose() {
    _animationController?.dispose();
    super.dispose();
  }
}

import 'dart:async';

import 'package:flutter/material.dart';
import 'package:flutter_fractals/core/services/animation_controller_service.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:vector_math/vector_math.dart' hide Colors;

void main() {
  TestWidgetsFlutterBinding.ensureInitialized();

  // ---------------------------------------------------------------------------
  // AnimatedFractalController
  // ---------------------------------------------------------------------------

  group('AnimatedFractalController – construction', () {
    test('creates with default durations and curve', () {
      final controller = AnimatedFractalController();

      expect(controller.parameterDuration, const Duration(milliseconds: 250));
      expect(controller.morphDuration, const Duration(milliseconds: 600));
      expect(controller.curve, Curves.easeOutCubic);
      expect(controller.isTransitioning, isFalse);
      expect(controller.isCelebrating, isFalse);
      expect(controller.morphProgress, 1.0);
      expect(controller.previousModuleId, isNull);
      expect(controller.currentModuleId, isNull);

      controller.dispose();
    });

    test('creates with custom durations and curve', () {
      final controller = AnimatedFractalController(
        parameterDuration: const Duration(milliseconds: 100),
        morphDuration: const Duration(milliseconds: 300),
        curve: Curves.linear,
      );

      expect(controller.parameterDuration, const Duration(milliseconds: 100));
      expect(controller.morphDuration, const Duration(milliseconds: 300));
      expect(controller.curve, Curves.linear);

      controller.dispose();
    });
  });

  // ---------------------------------------------------------------------------
  // AnimatedParameterTransitionPlan
  // ---------------------------------------------------------------------------

  group('AnimatedParameterTransitionPlan', () {
    test('classifies unchanged, numeric, and unsupported parameter changes',
        () {
      final unchanged = AnimatedParameterTransitionPlan.fromValues(1.0, 1.0);
      final numeric = AnimatedParameterTransitionPlan.fromValues(1, 2.5);
      final unsupported =
          AnimatedParameterTransitionPlan.fromValues(false, true);

      expect(unchanged.kind, AnimatedParameterTransitionKind.unchanged);
      expect(unchanged.startsTransition, isFalse);
      expect(numeric.kind, AnimatedParameterTransitionKind.numeric);
      expect(numeric.startsTransition, isTrue);
      expect(numeric.fromValue, 1.0);
      expect(numeric.toValue, 2.5);
      expect(unsupported.kind, AnimatedParameterTransitionKind.unsupported);
      expect(unsupported.startsTransition, isFalse);
    });
  });

  // ---------------------------------------------------------------------------
  // AnimatedTimelinePlan
  // ---------------------------------------------------------------------------

  group('AnimatedTimelinePlan', () {
    test('keeps sub-frame durations inside the curve progress domain', () {
      final plan = AnimatedTimelinePlan.forDuration(
        const Duration(milliseconds: 1),
      );

      expect(plan.isImmediate, isFalse);
      expect(plan.totalFrames, 1);
      expect(plan.progressForFrame(0), 0.0);
      expect(plan.progressForFrame(1), 1.0);
      expect(plan.progressForFrame(2), 1.0);
      expect(plan.isCompleteFrame(1), isTrue);
    });

    test('treats zero and negative durations as immediate one-frame plans', () {
      for (final duration in [
        Duration.zero,
        const Duration(milliseconds: -1),
      ]) {
        final plan = AnimatedTimelinePlan.forDuration(duration);

        expect(plan.isImmediate, isTrue, reason: '$duration');
        expect(plan.totalFrames, 1, reason: '$duration');
        expect(plan.progressForFrame(1), 1.0, reason: '$duration');
      }
    });
  });

  // ---------------------------------------------------------------------------
  // AnimatedElapsedProgress
  // ---------------------------------------------------------------------------

  group('AnimatedElapsedProgress', () {
    test('treats non-positive durations as immediate completion', () {
      for (final duration in [
        Duration.zero,
        const Duration(milliseconds: -1),
      ]) {
        final progress = AnimatedElapsedProgress(
          duration: duration,
          elapsed: Duration.zero,
        );

        expect(progress.value, 1.0, reason: '$duration');
        expect(progress.isComplete, isTrue, reason: '$duration');
      }
    });

    test('clamps positive-duration elapsed progress to the curve domain', () {
      expect(
        const AnimatedElapsedProgress(
          duration: Duration(seconds: 1),
          elapsed: Duration(milliseconds: -1),
        ).value,
        0.0,
      );
      expect(
        const AnimatedElapsedProgress(
          duration: Duration(seconds: 1),
          elapsed: Duration(milliseconds: 500),
        ).value,
        0.5,
      );
      expect(
        const AnimatedElapsedProgress(
          duration: Duration(seconds: 1),
          elapsed: Duration(seconds: 2),
        ).value,
        1.0,
      );
    });
  });

  // ---------------------------------------------------------------------------
  // Interpolated value accessors before any animation starts
  // ---------------------------------------------------------------------------

  group('AnimatedFractalController – initial interpolated values', () {
    test('interpolatedZoom is null before animateZoom is called', () {
      final controller = AnimatedFractalController();
      expect(controller.interpolatedZoom, isNull);
      controller.dispose();
    });

    test('interpolatedPan is null before animatePan is called', () {
      final controller = AnimatedFractalController();
      expect(controller.interpolatedPan, isNull);
      controller.dispose();
    });

    test('interpolatedRotation is null before animateRotation is called', () {
      final controller = AnimatedFractalController();
      expect(controller.interpolatedRotation, isNull);
      controller.dispose();
    });

    test('getInterpolatedValue returns null for unknown parameter id', () {
      final controller = AnimatedFractalController();
      expect(controller.getInterpolatedValue('nonexistent', 42.0), isNull);
      controller.dispose();
    });
  });

  // ---------------------------------------------------------------------------
  // animateParameter
  // ---------------------------------------------------------------------------

  group('AnimatedFractalController – animateParameter', () {
    test('sets isTransitioning to true when animating a numeric parameter', () {
      final controller = AnimatedFractalController();

      controller.animateParameter('speed', 0.0, 1.0);

      expect(controller.isTransitioning, isTrue);

      controller.dispose();
    });

    test('no-op when from == to', () {
      final controller = AnimatedFractalController();
      bool notified = false;
      controller.addListener(() => notified = true);

      controller.animateParameter('speed', 1.0, 1.0);

      // from == to → function returns early; no notification is emitted
      expect(notified, isFalse);
      expect(controller.isTransitioning, isFalse);

      controller.dispose();
    });

    test('unsupported parameter changes do not leave transitions stuck', () {
      final controller = AnimatedFractalController();
      int notifyCount = 0;
      controller.addListener(() => notifyCount++);

      controller.animateParameter('enabled', false, true);
      controller.tick();

      expect(controller.isTransitioning, isFalse);
      expect(controller.getInterpolatedValue('enabled', true), isNull);
      expect(notifyCount, 0);

      controller.dispose();
    });

    test('notifies listeners when parameter animation starts', () {
      final controller = AnimatedFractalController();
      int notifyCount = 0;
      controller.addListener(() => notifyCount++);

      controller.animateParameter('iterations', 100.0, 200.0);

      expect(notifyCount, greaterThan(0));

      controller.dispose();
    });

    test('returns an interpolated value between from and to', () {
      final controller = AnimatedFractalController(
        parameterDuration: const Duration(milliseconds: 500),
      );

      controller.animateParameter('zoom', 0.0, 100.0);

      // Immediately after start the animation is in-flight; value must be in [0, 100].
      final value = controller.getInterpolatedValue('zoom', 0.0);
      expect(value, isA<double>());
      expect(value as double, inInclusiveRange(0.0, 100.0));

      controller.dispose();
    });
  });

  // ---------------------------------------------------------------------------
  // animateZoom
  // ---------------------------------------------------------------------------

  group('AnimatedFractalController – animateZoom', () {
    test('sets isTransitioning and produces a non-null interpolated zoom', () {
      final controller = AnimatedFractalController(
        parameterDuration: const Duration(milliseconds: 500),
      );

      controller.animateZoom(1.0, 5.0);

      expect(controller.isTransitioning, isTrue);
      expect(controller.interpolatedZoom, isNotNull);
      expect(controller.interpolatedZoom!, inInclusiveRange(1.0, 5.0));

      controller.dispose();
    });

    test('no-op when from == to', () {
      final controller = AnimatedFractalController();

      controller.animateZoom(2.0, 2.0);

      expect(controller.isTransitioning, isFalse);
      expect(controller.interpolatedZoom, isNull);

      controller.dispose();
    });
  });

  // ---------------------------------------------------------------------------
  // animatePan
  // ---------------------------------------------------------------------------

  group('AnimatedFractalController – animatePan', () {
    test('sets isTransitioning and provides an in-range interpolated pan', () {
      final controller = AnimatedFractalController(
        parameterDuration: const Duration(milliseconds: 500),
      );
      final from = Vector2(0.0, 0.0);
      final to = Vector2(1.0, 1.0);

      controller.animatePan(from, to);

      expect(controller.isTransitioning, isTrue);
      expect(controller.interpolatedPan, isNotNull);
      final pan = controller.interpolatedPan!;
      expect(pan.x, inInclusiveRange(0.0, 1.0));
      expect(pan.y, inInclusiveRange(0.0, 1.0));

      controller.dispose();
    });

    test('no-op when from and to are identical', () {
      final controller = AnimatedFractalController();

      controller.animatePan(Vector2(0.5, 0.5), Vector2(0.5, 0.5));

      expect(controller.isTransitioning, isFalse);
      expect(controller.interpolatedPan, isNull);

      controller.dispose();
    });
  });

  // ---------------------------------------------------------------------------
  // animateRotation
  // ---------------------------------------------------------------------------

  group('AnimatedFractalController – animateRotation', () {
    test('sets isTransitioning and provides an in-range interpolated rotation',
        () {
      final controller = AnimatedFractalController(
        parameterDuration: const Duration(milliseconds: 500),
      );
      final from = Vector3(0.0, 0.0, 0.0);
      final to = Vector3(1.0, 2.0, 3.0);

      controller.animateRotation(from, to);

      expect(controller.isTransitioning, isTrue);
      expect(controller.interpolatedRotation, isNotNull);
      final rot = controller.interpolatedRotation!;
      expect(rot.x, inInclusiveRange(0.0, 1.0));
      expect(rot.y, inInclusiveRange(0.0, 2.0));
      expect(rot.z, inInclusiveRange(0.0, 3.0));

      controller.dispose();
    });

    test('no-op when from and to are identical', () {
      final controller = AnimatedFractalController();

      controller.animateRotation(Vector3(1, 2, 3), Vector3(1, 2, 3));

      expect(controller.isTransitioning, isFalse);
      expect(controller.interpolatedRotation, isNull);

      controller.dispose();
    });
  });

  // ---------------------------------------------------------------------------
  // startMorph
  // ---------------------------------------------------------------------------

  group('AnimatedFractalController – startMorph', () {
    test('sets isTransitioning, previousModuleId, and currentModuleId', () {
      final controller = AnimatedFractalController();

      controller.startMorph('mandelbrot', 'julia');

      expect(controller.isTransitioning, isTrue);
      expect(controller.previousModuleId, 'mandelbrot');
      expect(controller.currentModuleId, 'julia');
      expect(controller.morphProgress, inInclusiveRange(0.0, 1.0));

      controller.dispose();
    });

    test('no-op when fromModuleId == toModuleId', () {
      final controller = AnimatedFractalController();

      controller.startMorph('julia', 'julia');

      expect(controller.isTransitioning, isFalse);
      expect(controller.previousModuleId, isNull);
      expect(controller.morphProgress, 1.0);

      controller.dispose();
    });

    test('cancels prior morph and starts a new one', () {
      final controller = AnimatedFractalController();

      controller.startMorph('mandelbrot', 'julia');
      controller.startMorph('julia', 'phoenix');

      expect(controller.currentModuleId, 'phoenix');
      expect(controller.previousModuleId, 'julia');

      controller.dispose();
    });

    test('sub-frame morph durations complete without invalid curve progress',
        () async {
      final controller = AnimatedFractalController(
        morphDuration: const Duration(milliseconds: 1),
      );

      controller.startMorph('mandelbrot', 'julia');
      await Future<void>.delayed(const Duration(milliseconds: 20));

      expect(controller.morphProgress, 1.0);
      expect(controller.previousModuleId, isNull);
      expect(controller.isTransitioning, isFalse);

      controller.dispose();
    });
  });

  // ---------------------------------------------------------------------------
  // tick
  // ---------------------------------------------------------------------------

  group('AnimatedFractalController – tick', () {
    test('tick does not throw when no animations are active', () {
      final controller = AnimatedFractalController();

      expect(() => controller.tick(), returnsNormally);

      controller.dispose();
    });

    test('tick advances active animations and notifies when running', () {
      final controller = AnimatedFractalController(
        parameterDuration: const Duration(milliseconds: 500),
      );
      controller.animateZoom(1.0, 10.0);

      int notifications = 0;
      controller.addListener(() => notifications++);

      controller.tick();

      // Animation is in-flight → tick should have triggered a notification
      expect(notifications, greaterThan(0));

      controller.dispose();
    });

    test('tick completes animation after duration elapses', () async {
      final controller = AnimatedFractalController(
        parameterDuration: const Duration(milliseconds: 1),
      );
      controller.animateZoom(0.0, 5.0);

      // Wait longer than parameterDuration so the animation is done
      await Future<void>.delayed(const Duration(milliseconds: 50));
      controller.tick();

      // After completion the zoom should be cleared and transitioning should stop
      expect(controller.interpolatedZoom, isNull);
      expect(controller.isTransitioning, isFalse);

      controller.dispose();
    });

    test('tick completes parameter animations without concurrent mutation',
        () async {
      final controller = AnimatedFractalController(
        parameterDuration: const Duration(milliseconds: 1),
      );

      try {
        controller.animateParameter('iterations', 100.0, 200.0);
        await Future<void>.delayed(const Duration(milliseconds: 50));

        expect(() => controller.tick(), returnsNormally);
        expect(controller.getInterpolatedValue('iterations', 200.0), isNull);
        expect(controller.isTransitioning, isFalse);
      } finally {
        controller.dispose();
      }
    });

    test('tick completes negative-duration animations instead of sticking', () {
      final controller = AnimatedFractalController(
        parameterDuration: const Duration(milliseconds: -1),
      );
      controller.animateZoom(0.0, 5.0);

      controller.tick();

      expect(controller.interpolatedZoom, isNull);
      expect(controller.isTransitioning, isFalse);

      controller.dispose();
    });
  });

  // ---------------------------------------------------------------------------
  // celebrate / recordInterestingSpot
  // ---------------------------------------------------------------------------

  group('AnimatedFractalController – celebrate', () {
    test('celebrate sets isCelebrating to true', () {
      final controller = AnimatedFractalController();

      controller.celebrate();

      expect(controller.isCelebrating, isTrue);

      controller.dispose();
    });

    test('celebrate notifies listeners', () {
      final controller = AnimatedFractalController();
      int notifyCount = 0;
      controller.addListener(() => notifyCount++);

      controller.celebrate();

      expect(notifyCount, greaterThan(0));

      controller.dispose();
    });
  });

  group('AnimatedFractalController – recordInterestingSpot', () {
    test('emits onInterestingSpot stream event', () async {
      final controller = AnimatedFractalController();
      final Completer<void> completer = Completer<void>();
      final sub = controller.onInterestingSpot.listen((_) {
        if (!completer.isCompleted) completer.complete();
      });

      controller.recordInterestingSpot();

      await completer.future.timeout(const Duration(seconds: 1));
      expect(completer.isCompleted, isTrue);

      await sub.cancel();
      controller.dispose();
    });

    test('triggers celebration after 3 quick interesting spots', () {
      final controller = AnimatedFractalController();

      controller.recordInterestingSpot();
      controller.recordInterestingSpot();
      controller.recordInterestingSpot();

      // Third call in quick succession triggers celebration
      expect(controller.isCelebrating, isTrue);

      controller.dispose();
    });

    test('does not trigger celebration when spots are spaced out', () async {
      // We cannot actually wait 30 s in a unit test, so we verify that two
      // quick spots do NOT yet trigger celebration (threshold is 3).
      final controller = AnimatedFractalController();

      controller.recordInterestingSpot();
      controller.recordInterestingSpot();

      expect(controller.isCelebrating, isFalse);

      controller.dispose();
    });
  });

  // ---------------------------------------------------------------------------
  // dispose
  // ---------------------------------------------------------------------------

  group('AnimatedFractalController – dispose', () {
    test('disposes cleanly with no active animations', () {
      final controller = AnimatedFractalController();

      expect(() => controller.dispose(), returnsNormally);
    });

    test('disposes cleanly while a morph is in progress', () {
      final controller = AnimatedFractalController();
      controller.startMorph('mandelbrot', 'julia');

      expect(() => controller.dispose(), returnsNormally);
    });

    test('disposes cleanly while zoom animation is in progress', () {
      final controller = AnimatedFractalController(
        parameterDuration: const Duration(seconds: 10),
      );
      controller.animateZoom(1.0, 100.0);

      expect(() => controller.dispose(), returnsNormally);
    });

    testWidgets('dispose cancels pending celebration reset callbacks',
        (tester) async {
      final controller = AnimatedFractalController();

      controller.celebrate();
      controller.dispose();
      await tester.pump(const Duration(milliseconds: 2500));

      expect(tester.takeException(), isNull);
    });
  });

  // ---------------------------------------------------------------------------
  // ChangeNotifier listener management
  // ---------------------------------------------------------------------------

  group('AnimatedFractalController – ChangeNotifier', () {
    test('addListener and removeListener work without errors', () {
      final controller = AnimatedFractalController();
      void listener() {}

      controller.addListener(listener);
      controller.removeListener(listener);

      // If removeListener does not throw, the test passes.
      controller.dispose();
    });
  });

  // ---------------------------------------------------------------------------
  // AnimatedFractalMixin (via a concrete subclass)
  // ---------------------------------------------------------------------------

  group('AnimatedFractalMixin', () {
    test('animationController is lazily created', () {
      final host = _MixinHost();

      // Accessing .animationController should create one on demand.
      expect(host.animationController, isA<AnimatedFractalController>());

      host.dispose();
    });

    test('custom animationController can be set', () {
      final host = _MixinHost();
      final custom = AnimatedFractalController(
        parameterDuration: const Duration(milliseconds: 99),
      );

      host.animationController = custom;

      expect(host.animationController.parameterDuration,
          const Duration(milliseconds: 99));

      host.dispose();
    });

    test('dispose of host also disposes the animation controller', () async {
      final host = _MixinHost();
      // Trigger lazy creation.
      final ctrl = host.animationController;

      // Should not throw.
      expect(() => host.dispose(), returnsNormally);

      // After the underlying StreamController is closed, listening to the
      // broadcast stream returns a subscription that immediately completes
      // (done) — it does NOT throw. Verify the stream is done by checking
      // that no further events can be emitted (the controller is closed).
      final events = <void>[];
      final sub = ctrl.onInterestingSpot.listen(events.add);
      await Future<void>.delayed(Duration.zero);
      await sub.cancel();
      // No events should arrive because the stream is already closed.
      expect(events, isEmpty);
    });
  });
}

