import 'dart:convert';

/// Tracks exploration statistics across sessions.
class ExplorationStats {
  final double totalZoomDistance;
  final int totalTimeSeconds;
  final int screenshotsTaken;
  final Set<String> uniqueFractalsExplored;
  final DateTime? firstExplorationDate;
  final DateTime lastUpdated;

  ExplorationStats({
    this.totalZoomDistance = 0.0,
    this.totalTimeSeconds = 0,
    this.screenshotsTaken = 0,
    Set<String>? uniqueFractalsExplored,
    this.firstExplorationDate,
    DateTime? lastUpdated,
  })  : uniqueFractalsExplored = uniqueFractalsExplored ?? {},
        lastUpdated = lastUpdated ?? DateTime.now();

  ExplorationStats copyWith({
    double? totalZoomDistance,
    int? totalTimeSeconds,
    int? screenshotsTaken,
    Set<String>? uniqueFractalsExplored,
    DateTime? firstExplorationDate,
    DateTime? lastUpdated,
  }) {
    return ExplorationStats(
      totalZoomDistance: totalZoomDistance ?? this.totalZoomDistance,
      totalTimeSeconds: totalTimeSeconds ?? this.totalTimeSeconds,
      screenshotsTaken: screenshotsTaken ?? this.screenshotsTaken,
      uniqueFractalsExplored: uniqueFractalsExplored ?? this.uniqueFractalsExplored,
      firstExplorationDate: firstExplorationDate ?? this.firstExplorationDate,
      lastUpdated: lastUpdated ?? DateTime.now(),
    );
  }

  Map<String, dynamic> toJson() => {
        'totalZoomDistance': totalZoomDistance,
        'totalTimeSeconds': totalTimeSeconds,
        'screenshotsTaken': screenshotsTaken,
        'uniqueFractalsExplored': uniqueFractalsExplored.toList(),
        'firstExplorationDate': firstExplorationDate?.toIso8601String(),
        'lastUpdated': lastUpdated.toIso8601String(),
      };

  factory ExplorationStats.fromJson(Map<String, dynamic> json) {
    return ExplorationStats(
      totalZoomDistance: (json['totalZoomDistance'] as num?)?.toDouble() ?? 0.0,
      totalTimeSeconds: json['totalTimeSeconds'] as int? ?? 0,
      screenshotsTaken: json['screenshotsTaken'] as int? ?? 0,
      uniqueFractalsExplored: (json['uniqueFractalsExplored'] as List<dynamic>?)
              ?.map((e) => e as String)
              .toSet() ??
          {},
      firstExplorationDate: json['firstExplorationDate'] != null
          ? DateTime.tryParse(json['firstExplorationDate'] as String)
          : null,
      lastUpdated: json['lastUpdated'] != null
          ? DateTime.tryParse(json['lastUpdated'] as String) ?? DateTime.now()
          : DateTime.now(),
    );
  }

  String encode() => jsonEncode(toJson());

  static ExplorationStats decode(String source) {
    try {
      return ExplorationStats.fromJson(jsonDecode(source) as Map<String, dynamic>);
    } catch (_) {
      return ExplorationStats();
    }
  }
}

import 'dart:async' show unawaited;
import 'dart:math';
import 'package:flutter/foundation.dart';
import 'package:shared_preferences/shared_preferences.dart';
import '../models/exploration_stats.dart';

/// Achievement definitions.
enum Achievement {
  firstZoom('First Zoom', 'Zoomed into a fractal', 0.25),
  zoomMaster('Zoom Master', 'Total zoom distance > 10', 10.0),
  firstScreenshot('First Screenshot', 'Took your first screenshot', 1),
  photographer('Photographer', 'Took 10 screenshots', 10),
  explorer('Explorer', 'Explored 5 different fractals', 5),
  veteran('Veteran', 'Spent 1 hour exploring', 3600);

  final String title;
  final String description;
  final num threshold;

  const Achievement(this.title, this.description, this.threshold);
}

/// Replayable telemetry normalization for exploration statistics.
///
/// UI/controller inputs are usually well-formed, but platform telemetry,
/// restored sessions, or test harnesses can pass NaN/Infinity or negative time.
/// Those samples should be ignored instead of poisoning totals that are later
/// persisted with JSON.
@visibleForTesting
final class ExplorationStatsTelemetry {
  const ExplorationStatsTelemetry._();

  static double? zoomDistance(double oldZoom, double newZoom) {
    if (!_isPositiveFinite(oldZoom) || !_isPositiveFinite(newZoom)) return null;
    final distance = (log(newZoom) - log(oldZoom)).abs();
    return distance.isFinite ? distance : null;
  }

  static double? directZoomDistance(double distance) {
    if (!distance.isFinite) return null;
    return distance.abs();
  }

  static int? exploredSeconds(int seconds) {
    return seconds > 0 ? seconds : null;
  }

  static bool _isPositiveFinite(double value) => value.isFinite && value > 0.0;
}

/// Service for tracking exploration statistics.
class ExplorationStatsService extends ChangeNotifier {
  static const _prefsKey = 'exploration_stats_v1';
  static const _achievementsKey = 'unlocked_achievements';

  ExplorationStats _stats = ExplorationStats();
  Set<Achievement> _unlockedAchievements = {};
  SharedPreferences? _prefs;

  ExplorationStats get stats => _stats;
  Set<Achievement> get unlockedAchievements => _unlockedAchievements;

  Future<void> init() async {
    _prefs = await SharedPreferences.getInstance();
    _load();
  }

  void _load() {
    final stored = _prefs?.getString(_prefsKey);
    if (stored != null) {
      _stats = ExplorationStats.decode(stored);
    }
    final achievements = _prefs?.getStringList(_achievementsKey) ?? [];
    _unlockedAchievements = achievements
        .map((name) {
          try {
            return Achievement.values.firstWhere((a) => a.name == name);
          } catch (e) {
            if (kDebugMode) debugPrint('[FF] silent catch: $e');
            return null;
          }
        })
        .whereType<Achievement>()
        .toSet();
  }

  Future<void> _save() async {
    await _prefs?.setString(_prefsKey, _stats.encode());
    await _prefs?.setStringList(
        _achievementsKey, _unlockedAchievements.map((a) => a.name).toList());
  }

  /// Record zoom distance traveled (pass absolute log ratio).
  void recordZoom(double oldZoom, double newZoom) {
    final distance = ExplorationStatsTelemetry.zoomDistance(oldZoom, newZoom);
    if (distance == null) return;
    _recordZoomDistance(distance);
  }

  /// Record time spent exploring.
  void recordTime(int seconds) {
    final safeSeconds = ExplorationStatsTelemetry.exploredSeconds(seconds);
    if (safeSeconds == null) return;

    _stats = _stats.copyWith(
      totalTimeSeconds: _stats.totalTimeSeconds + safeSeconds,
    );
    _checkAchievements();
    unawaited(_save());
    notifyListeners();
  }

  /// Alias for recordTime for compatibility (accepts Duration).
  void addExploreTime(Duration duration) => recordTime(duration.inSeconds);

  /// Alias for recordZoom that takes a distance directly.
  void addZoomDistance(double distance) {
    final safeDistance = ExplorationStatsTelemetry.directZoomDistance(distance);
    if (safeDistance == null) return;
    _recordZoomDistance(safeDistance);
  }

  void _recordZoomDistance(double distance) {
    _stats = _stats.copyWith(
      totalZoomDistance: _stats.totalZoomDistance + distance,
      firstExplorationDate: _stats.firstExplorationDate ?? DateTime.now(),
    );
    _checkAchievements();
    unawaited(_save());
    notifyListeners();
  }

  /// Record a screenshot/export.
  void recordScreenshot() {
    _stats = _stats.copyWith(
      screenshotsTaken: _stats.screenshotsTaken + 1,
    );
    _checkAchievements();
    unawaited(_save());
    notifyListeners();
  }

  /// Record exploring a fractal module.
  void recordFractalExplored(String moduleId) {
    final updated = Set<String>.from(_stats.uniqueFractalsExplored)
      ..add(moduleId);
    _stats = _stats.copyWith(
      uniqueFractalsExplored: updated,
      firstExplorationDate: _stats.firstExplorationDate ?? DateTime.now(),
    );
    _checkAchievements();
    unawaited(_save());
    notifyListeners();
  }

  void _checkAchievements() {
    final newlyUnlocked = <Achievement>[];

    if (!_unlockedAchievements.contains(Achievement.firstZoom) &&
        _stats.totalZoomDistance >= Achievement.firstZoom.threshold) {
      newlyUnlocked.add(Achievement.firstZoom);
    }
    if (!_unlockedAchievements.contains(Achievement.zoomMaster) &&
        _stats.totalZoomDistance >= Achievement.zoomMaster.threshold) {
      newlyUnlocked.add(Achievement.zoomMaster);
    }
    if (!_unlockedAchievements.contains(Achievement.firstScreenshot) &&
        _stats.screenshotsTaken >= Achievement.firstScreenshot.threshold) {
      newlyUnlocked.add(Achievement.firstScreenshot);
    }
    if (!_unlockedAchievements.contains(Achievement.photographer) &&
        _stats.screenshotsTaken >= Achievement.photographer.threshold) {
      newlyUnlocked.add(Achievement.photographer);
    }
    if (!_unlockedAchievements.contains(Achievement.explorer) &&
        _stats.uniqueFractalsExplored.length >=
            Achievement.explorer.threshold) {
      newlyUnlocked.add(Achievement.explorer);
    }
    if (!_unlockedAchievements.contains(Achievement.veteran) &&
        _stats.totalTimeSeconds >= Achievement.veteran.threshold) {
      newlyUnlocked.add(Achievement.veteran);
    }

    if (newlyUnlocked.isNotEmpty) {
      _unlockedAchievements = {..._unlockedAchievements, ...newlyUnlocked};
    }
  }

  /// Get progress toward an achievement (0.0 to 1.0).
  double getProgress(Achievement achievement) {
    if (_unlockedAchievements.contains(achievement)) return 1.0;

    final current = switch (achievement) {
      Achievement.firstZoom ||
      Achievement.zoomMaster =>
        _stats.totalZoomDistance,
      Achievement.firstScreenshot ||
      Achievement.photographer =>
        _stats.screenshotsTaken.toDouble(),
      Achievement.explorer => _stats.uniqueFractalsExplored.length.toDouble(),
      Achievement.veteran => _stats.totalTimeSeconds.toDouble(),
    };

    return (current / achievement.threshold.toDouble()).clamp(0.0, 1.0);
  }
}

import 'package:flutter_test/flutter_test.dart';
import 'package:shared_preferences/shared_preferences.dart';
import 'package:flutter_fractals/core/services/exploration_stats_service.dart';

void main() {
  group('ExplorationStatsService', () {
    late ExplorationStatsService service;

    setUp(() async {
      SharedPreferences.setMockInitialValues({});
      service = ExplorationStatsService();
      await service.init();
    });

    test('starts with empty stats', () {
      expect(service.stats.totalZoomDistance, 0.0);
      expect(service.stats.totalTimeSeconds, 0);
      expect(service.stats.screenshotsTaken, 0);
      expect(service.stats.uniqueFractalsExplored, isEmpty);
    });

    test('recordZoom adds distance to total', () {
      service.recordZoom(1.0, 10.0);
      // log(10) - log(1) = ln(10) ≈ 2.302
      expect(service.stats.totalZoomDistance, greaterThan(0.0));

      final before = service.stats.totalZoomDistance;
      service.recordZoom(1.0, 100.0);
      expect(service.stats.totalZoomDistance, greaterThan(before));
    });

    test('ignores malformed zoom telemetry instead of corrupting progress', () {
      service.recordZoom(1.0, double.infinity);
      service.recordZoom(double.nan, 10.0);
      service.addZoomDistance(double.nan);
      service.addZoomDistance(double.infinity);

      expect(service.stats.totalZoomDistance, 0.0);
      expect(
          service.unlockedAchievements, isNot(contains(Achievement.firstZoom)));
      expect(service.getProgress(Achievement.firstZoom), 0.0);
    });

    test('recordTime accumulates total seconds', () {
      service.recordTime(60);
      expect(service.stats.totalTimeSeconds, equals(60));

      service.recordTime(120);
      expect(service.stats.totalTimeSeconds, equals(180));
    });

    test('ignores negative time telemetry instead of reducing totals', () {
      service.recordTime(60);
      service.recordTime(-120);
      service.addExploreTime(const Duration(seconds: -30));

      expect(service.stats.totalTimeSeconds, 60);
      expect(service.getProgress(Achievement.veteran), greaterThan(0.0));
    });

    test('recordScreenshot increments count', () {
      service.recordScreenshot();
      expect(service.stats.screenshotsTaken, equals(1));

      service.recordScreenshot();
      expect(service.stats.screenshotsTaken, equals(2));
    });

    test('recordFractalExplored adds unique module IDs', () {
      service.recordFractalExplored('mandelbrot');
      service.recordFractalExplored('julia');
      expect(service.stats.uniqueFractalsExplored,
          containsAll(['mandelbrot', 'julia']));
      expect(service.stats.uniqueFractalsExplored.length, equals(2));
    });

    test('recordFractalExplored deduplicates same module', () {
      service.recordFractalExplored('mandelbrot');
      service.recordFractalExplored('mandelbrot');
      expect(service.stats.uniqueFractalsExplored.length, equals(1));
    });

    test('getProgress returns 1.0 for unlocked achievements', () {
      // Unlock firstZoom by recording enough distance (threshold 0.25).
      // log(e^0.3) - log(1) = 0.3 > 0.25
      service.recordZoom(1.0, 1.35); // distance ≈ 0.3
      expect(service.unlockedAchievements, contains(Achievement.firstZoom));
      expect(service.getProgress(Achievement.firstZoom), equals(1.0));
    });

    test('getProgress returns fractional progress for partial achievement', () {
      // photographer threshold is 10 screenshots; take 5.
      for (var i = 0; i < 5; i++) {
        service.recordScreenshot();
      }
      final progress = service.getProgress(Achievement.photographer);
      expect(progress, closeTo(0.5, 0.01));
    });
  });
}

